sql:
SELECT name, current_population, income_group_id
FROM countries
WHERE current_population = (
    SELECT MAX(current_population)
    FROM countries
);

SELECT year, AVG(gdp_growth_rate) AS avg_gdp_growth_rate
FROM economic_indicators
GROUP BY year;

SELECT name, (CUME_DIST() OVER (ORDER BY current_population)) AS cumulative_distribution
FROM countries
ORDER BY current_population;

SELECT countries.name AS Country, income_groups.name AS Income_Group
FROM countries
INNER JOIN income_groups ON countries.income_group_id = income_groups.income_group_id;

SELECT *
FROM health_stats
WHERE country_id = 0 AND year = 2021 AND life_expectancy = 77.3;

external_knowledge:
- "vast ocean of humanity" refers to the collection of countries;
- "navigated past the monumental threshold of 50 million souls" means countries where the current population (current_population) is greater than 50 million;
- "average wave of their populace" metaphorically refers to the average of the current population;
- The order is determined by the descending order of the average population.
